"use strict";(globalThis.webpackChunkdocusaurus_site=globalThis.webpackChunkdocusaurus_site||[]).push([[95149],{77176(e,r,a){a.r(r),a.d(r,{assets:()=>u,contentTitle:()=>s,default:()=>l,frontMatter:()=>i,metadata:()=>o,toc:()=>m});const o=JSON.parse('{"id":"UserGuide/C23_Data_buffers/S18_Advanced_memory_management","title":"Advanced memory management","description":"When installing Aurora Imaging Library, the default setup asks the operating system to reserve a portion of RAM from the non-paged memory pool for Aurora Imaging Library. By default, this reserved portion of non-paged memory is a single contiguous block that Aurora Imaging Library typically uses for grab buffers. The default is usually sufficient and no further action is required on your part. On occasion, it might be necessary to alter how Aurora Imaging Library manages this memory. This can occur when you need large buffers and/or a large number of buffers for your application, as well as when you are changing the amount of RAM or the number of PCI devices, such as boards, in your computer.","source":"@site/docs/UserGuide/C23_Data_buffers/S18_Advanced_memory_management.md","sourceDirName":"UserGuide/C23_Data_buffers","slug":"/UserGuide/C23_Data_buffers/S18_Advanced_memory_management","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C23_Data_buffers/S18_Advanced_memory_management","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"doctype":"UserGuide","part":"2D related information","chapter":"Data_buffers","section":"Advanced_memory_management","module_tag":"buf","product":"Aurora-Imaging-Library-user-guide","version":1100,"path":"UserGuide / 2D related information / data-buffers / Advanced memory management"},"sidebar":"userGuideSidebar","previous":{"title":"Buffer overscan region","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C23_Data_buffers/S17_Buffer_overscan"},"next":{"title":"Lookup tables","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C24_Lookup_tables/ChapterInformation"}}');var n=a(74848),t=a(28453);const i={doctype:"UserGuide",part:"2D related information",chapter:"Data_buffers",section:"Advanced_memory_management",module_tag:"buf",product:"Aurora-Imaging-Library-user-guide",version:1100,path:"UserGuide / 2D related information / data-buffers / Advanced memory management"},s="Advanced memory management",u={},m=[{value:"Aurora Imaging Library non-paged memory management driver",id:"aurora-imaging-library-non-paged-memory-management-driver",level:2},{value:"Large non-paged Aurora Imaging Library buffers",id:"large-non-paged-aurora-imaging-library-buffers",level:3},{value:"On-Demand Mode",id:"on-demand-mode",level:3}];function d(e){const r={blockquote:"blockquote",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",strong:"strong",...(0,t.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(r.header,{children:(0,n.jsx)(r.h1,{id:"advanced-memory-management",children:"Advanced memory management"})}),"\n",(0,n.jsx)(r.p,{children:"When installing Aurora Imaging Library, the default setup asks the operating system to reserve a portion of RAM from the non-paged memory pool for Aurora Imaging Library. By default, this reserved portion of non-paged memory is a single contiguous block that Aurora Imaging Library typically uses for grab buffers. The default is usually sufficient and no further action is required on your part. On occasion, it might be necessary to alter how Aurora Imaging Library manages this memory. This can occur when you need large buffers and/or a large number of buffers for your application, as well as when you are changing the amount of RAM or the number of PCI devices, such as boards, in your computer."}),"\n",(0,n.jsxs)(r.p,{children:["To make adjustments to Aurora Imaging Library's non-paged memory setup, especially the non-paged memory size reserved for Aurora Imaging Library, use the Aurora Imaging Configurator utility under the ",(0,n.jsx)(r.strong,{children:"Non-paged memory"})," item."]}),"\n",(0,n.jsx)(r.h2,{id:"aurora-imaging-library-non-paged-memory-management-driver",children:"Aurora Imaging Library non-paged memory management driver"}),"\n",(0,n.jsx)(r.p,{children:"The Aurora Imaging Library non-paged memory management driver uses the operating system's mechanism to reserve the total amount of non-paged memory required for Aurora Imaging Library. The mechanism allocates non-paged memory into non-adjacent chunks of contiguous memory. The chunk size depends upon the total RAM installed in your computer, but the size is only relevant if the total non-paged memory requested for Aurora Imaging Library is greater than the size of a single chunk. If you request 1 Gbyte of non-paged memory and, based on the amount of RAM in your computer, the chunk size is 256 Mbytes, you will have 4 non-adjacent 256-Mbyte chunks of contiguous memory. In this example, if you allocate two 100 Mbyte grab buffers, they could both exist in a single chunk, but if you allocate two 150 Mbyte grab buffers, they would each occupy a separate chunk, since a single buffer cannot occupy two separate chunks. Aurora Imaging Library will not allow you to allocate a buffer larger than the chunk size, by default. To allow very large buffers, you must enable large non-paged Aurora Imaging Library buffers using the Aurora Imaging Configurator utility."}),"\n",(0,n.jsxs)(r.blockquote,{children:["\n",(0,n.jsxs)(r.p,{children:[(0,n.jsx)(r.strong,{children:"Note:"})," Note that you might have installed Aurora Imaging Library without installing the Aurora Imaging Library non-paged memory management driver; this can happen if no boards were selected during Aurora Imaging Library installation. If this is the case, there will be no Aurora Imaging Configurator utility option to adjust non-paged memory, since there is no driver able to reserve non-paged memory for Aurora Imaging Library; consequently, there will be no non-paged memory available for your application. To install the Aurora Imaging Library non-paged memory manager driver, you must uninstall and re-install Aurora Imaging Library."]}),"\n"]}),"\n",(0,n.jsx)(r.h3,{id:"large-non-paged-aurora-imaging-library-buffers",children:"Large non-paged Aurora Imaging Library buffers"}),"\n",(0,n.jsx)(r.p,{children:"If your application needs individual buffers that are larger than the chunk size, such as for line-scan cameras, you can explicitly allow the Aurora Imaging Library non-paged memory management driver to re-allocate memory such that chunk sizes are ignored when allocating buffers. However, if afterwards, you change either the PCI devices in your computer, or the total amount of RAM, the original re-allocation of memory that allowed large non-paged Aurora Imaging Library buffers can lead to the problem of memory conflicts and/or an unusable block of memory."}),"\n",(0,n.jsxs)(r.p,{children:["To resolve these problems, you should use a tool in the Aurora Imaging Configurator utility that respects both the amount of non-paged memory you reserved for Aurora Imaging Library and the new hardware setup. This two button tool is found in the ",(0,n.jsx)(r.strong,{children:"Error Detection"})," sub-item under the ",(0,n.jsx)(r.strong,{children:"Non-paged memory"})," item. Any user can click on the ",(0,n.jsx)(r.strong,{children:"Check Errors"})," button to assess if a hardware change created conflicts or waste, but only an administrator can click on the ",(0,n.jsx)(r.strong,{children:"Repair Errors"})," button to repair the issue. This tool can also be setup to run automatically immediately after logging in. To do so, select the ",(0,n.jsx)(r.strong,{children:"Check errors at each reboot and each time the Aurora Imaging Configurator utility starts"})," option and/or the ",(0,n.jsx)(r.strong,{children:"Fix problems when found"})," option. If an error is found while the tool is running, an error message will appear prompting you for further action to repair the issue. If the ",(0,n.jsx)(r.strong,{children:"Fix problems when found"})," option was selected and you logged in as an administrator, the problem will be fixed and a message box will appear prompting a reboot."]}),"\n",(0,n.jsx)(r.p,{children:"You must allow the tool to reboot twice for the fix to take effect."}),"\n",(0,n.jsxs)(r.blockquote,{children:["\n",(0,n.jsxs)(r.p,{children:[(0,n.jsx)(r.strong,{children:"Note:"})," Note that if a conflict occurs that crashes your computer and prevents a normal boot, press and hold ",(0,n.jsx)(r.strong,{children:"F8"})," while your computer is booting to enter safe mode. Once in safe mode, open the Aurora Imaging Configurator utility and click on the ",(0,n.jsx)(r.strong,{children:"Check Errors"})," button followed by the ",(0,n.jsx)(r.strong,{children:"Repair Errors"})," button. When Windows is running in safe mode, the Aurora Imaging Configurator utility's On-Demand mode is enabled by default, and there is no non-paged memory reserved."]}),"\n"]}),"\n",(0,n.jsx)(r.h3,{id:"on-demand-mode",children:"On-Demand Mode"}),"\n",(0,n.jsxs)(r.p,{children:["If your Aurora Imaging Library application sporadically needs more non-paged memory than what was reserved, or the maximum usage is unknown and you want to minimize non-paged reservation, increasing the amount of non-paged memory reserved for Aurora Imaging Library might be counterproductive. To accommodate this type of application, enable On-demand mode using the Aurora Imaging Configurator utility; the option can be found through the ",(0,n.jsx)(r.strong,{children:"Non-paged memory"})," item. This mode allows Aurora Imaging Library to use RAM outside of the non-paged memory reserved for Aurora Imaging Library. This mode should be used with caution because the memory outside of the non-paged memory reserved for Aurora Imaging Library is taken from the operating system's non-paged memory pool. If the pool is ever exhausted, this might lead to a system crash because of a failed memory allocation by another application or driver."]})]})}function l(e={}){const{wrapper:r}={...(0,t.R)(),...e.components};return r?(0,n.jsx)(r,{...e,children:(0,n.jsx)(d,{...e})}):d(e)}},28453(e,r,a){a.d(r,{R:()=>i,x:()=>s});var o=a(96540);const n={},t=o.createContext(n);function i(e){const r=o.useContext(t);return o.useMemo(function(){return"function"==typeof e?e(r):{...r,...e}},[r,e])}function s(e){let r;return r=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:i(e.components),o.createElement(t.Provider,{value:r},e.children)}}}]);